def find_all(text, pattern):
    """Rabin-Karp with large prime modulus."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    MOD = (1 << 61) - 1  # Mersenne prime for fast modular arithmetic
    BASE = 131
    # Compute BASE^(m-1) mod MOD
    power = 1
    for _ in range(m - 1):
        power = (power * BASE) % MOD
    # Hash the pattern
    pat_hash = 0
    for c in pattern:
        pat_hash = (pat_hash * BASE + ord(c)) % MOD
    # Hash the first window
    win_hash = 0
    for i in range(m):
        win_hash = (win_hash * BASE + ord(text[i])) % MOD
    result = []
    for i in range(n - m + 1):
        if win_hash == pat_hash:
            # Verify to avoid false positives
            match = True
            for k in range(m):
                if text[i + k] != pattern[k]:
                    match = False
                    break
            if match:
                result.append(i)
        # Roll the hash forward
        if i + m < n:
            win_hash = ((win_hash - ord(text[i]) * power) * BASE + ord(text[i + m])) % MOD
            if win_hash < 0:
                win_hash += MOD
    return result

def find_all(text, pattern):
    """KMP with optimized prefix function."""
    m = len(pattern)
    n = len(text)
    if m == 0 or m > n:
        return []
    # Build prefix (failure) function
    pi = [0] * m
    k = 0
    for q in range(1, m):
        while k > 0 and pattern[k] != pattern[q]:
            k = pi[k - 1]
        if pattern[k] == pattern[q]:
            k += 1
        pi[q] = k
    # Search
    matches = []
    q = 0
    for i in range(n):
        while q > 0 and pattern[q] != text[i]:
            q = pi[q - 1]
        if pattern[q] == text[i]:
            q += 1
        if q == m:
            matches.append(i - m + 1)
            q = pi[q - 1]
    return matches

def find_all(text, pattern):
    """Boyer-Moore-Horspool with last-occurrence heuristic."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    # Build skip table
    skip = {}
    for k in range(m - 1):
        skip[pattern[k]] = m - k - 1
    result = []
    i = m - 1  # index in text
    while i < n:
        j = m - 1  # index in pattern
        k = i
        while j >= 0 and text[k] == pattern[j]:
            j -= 1
            k -= 1
        if j == -1:
            result.append(k + 1)
            i += 1
        else:
            i += skip.get(text[i], m)
    return result

def find_all(text, pattern):
    """Bitap / shift-and algorithm for exact matching."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    if m > 64:
        # Fallback for patterns longer than word size
        result = []
        for i in range(n - m + 1):
            j = 0
            while j < m and text[i + j] == pattern[j]:
                j += 1
            if j == m:
                result.append(i)
        return result
    # Build bitmasks for each character
    B = {}
    for i in range(m):
        c = pattern[i]
        if c not in B:
            B[c] = 0
        B[c] |= (1 << i)
    result = []
    D = 0  # state bitvector
    match_mask = 1 << (m - 1)
    for i in range(n):
        D = ((D << 1) | 1) & B.get(text[i], 0)
        if D & match_mask:
            result.append(i - m + 1)
    return result

def find_all(text, pattern):
    """Z-function string matching."""
    m = len(pattern)
    n = len(text)
    if m == 0 or m > n:
        return []
    combined = pattern + '#' + text
    clen = len(combined)
    z = [0] * clen
    left = 0
    right = 0
    for i in range(1, clen):
        if i <= right:
            z[i] = min(right - i + 1, z[i - left])
        while i + z[i] < clen and combined[z[i]] == combined[i + z[i]]:
            z[i] += 1
        if i + z[i] - 1 > right:
            left = i
            right = i + z[i] - 1
    result = []
    sep = m + 1  # length of pattern + separator
    for i in range(sep, clen):
        if z[i] >= m:
            result.append(i - sep)
    return result

def find_all(text, pattern):
    """Not-So-Naive algorithm (improved naive with two-character check)."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    if m == 1:
        return [i for i in range(n) if text[i] == pattern[0]]
    result = []
    # Determine shift based on first two characters of pattern
    if pattern[0] != pattern[1]:
        k = 2  # shift by 2 when first char matches but second doesn't
    else:
        k = 1
    i = 0
    while i <= n - m:
        # Compare from position 1 first (skip position 0 initially)
        if pattern[1] == text[i + 1]:
            # Now check the rest
            j = 0
            while j < m and text[i + j] == pattern[j]:
                j += 1
            if j == m:
                result.append(i)
            # If text[i] matched pattern[0] but pattern[1] != text[i+1]
            # we would have skipped. Since we're here, shift by 1.
            i += k if text[i] == pattern[0] else 1
        else:
            # pattern[1] != text[i+1], can shift further
            i += 1
    return result
